INSERT INTO drug_categories (drug_categories_id, code, name, description) VALUES
('DCAT_ANTIBIOTIC', 'ANTIBIOTIC', 'Kháng sinh', 'Nhóm thuốc kháng sinh diệt khuẩn và kìm khuẩn (Penicillin, Cephalosporin, Macrolide, Quinolone...)'),
('DCAT_NSAID', 'NSAID', 'Giảm đau - Kháng viêm NSAIDs', 'Thuốc giảm đau, hạ sốt, kháng viêm không steroid (Ibuprofen, Diclofenac, Meloxicam...)'),
('DCAT_ANALGESIC', 'ANALGESIC', 'Giảm đau - Hạ sốt', 'Thuốc giảm đau và hạ sốt thông thường (Paracetamol, Tramadol...)'),
('DCAT_CARDIO', 'CARDIOVASCULAR', 'Tim mạch', 'Thuốc điều trị bệnh tim mạch, huyết áp, rối loạn nhịp tim'),
('DCAT_DIABET', 'ANTIDIABETIC', 'Đái tháo đường', 'Thuốc điều trị đái tháo đường type 1 và type 2'),
('DCAT_LIPID', 'LIPID_LOWERING', 'Hạ lipid máu', 'Thuốc điều trị rối loạn lipid máu, giảm cholesterol'),
('DCAT_GI', 'GASTROINTESTINAL', 'Tiêu hóa', 'Thuốc điều trị bệnh lý đường tiêu hóa (dạ dày, ruột, gan mật)'),
('DCAT_RESPIR', 'RESPIRATORY', 'Hô hấp', 'Thuốc điều trị bệnh lý đường hô hấp (hen, COPD, ho, long đờm)'),
('DCAT_NEURO', 'NEUROLOGICAL', 'Thần kinh', 'Thuốc tác dụng trên hệ thần kinh (an thần, chống co giật, migraine)'),
('DCAT_CORTICO', 'CORTICOSTEROID', 'Corticosteroid', 'Thuốc kháng viêm steroid (Prednisolone, Dexamethasone, Methylprednisolone)'),
('DCAT_ANTIHIST', 'ANTIHISTAMINE', 'Kháng Histamine - Chống dị ứng', 'Thuốc chống dị ứng, kháng histamine H1 (Cetirizine, Loratadine, Fexofenadine)'),
('DCAT_VITAMIN', 'VITAMIN_MINERAL', 'Vitamin & Khoáng chất', 'Bổ sung vitamin, khoáng chất, vi chất dinh dưỡng'),
('DCAT_ANTICOAG', 'ANTICOAGULANT', 'Chống đông máu', 'Thuốc chống đông, chống kết tập tiểu cầu (Warfarin, Clopidogrel, Enoxaparin)'),
('DCAT_DERMA', 'DERMATOLOGICAL', 'Da liễu', 'Thuốc bôi ngoài da, kem dưỡng, trị nấm, viêm da'),
('DCAT_OPHTHAL', 'OPHTHALMIC', 'Nhãn khoa', 'Thuốc nhỏ mắt, tra mắt điều trị bệnh lý mắt'),
('DCAT_ENT', 'ENT', 'Tai - Mũi - Họng', 'Thuốc xịt mũi, nhỏ tai, súc họng điều trị TMH'),
('DCAT_MUSCLE', 'MUSCLE_RELAXANT', 'Giãn cơ', 'Thuốc giãn cơ vân, giảm co thắt cơ (Eperisone, Thiocolchicoside)'),
('DCAT_UROLOGY', 'UROLOGY', 'Tiết niệu - Sinh dục', 'Thuốc điều trị bệnh lý tiết niệu, sỏi thận, phì đại tuyến tiền liệt'),
('DCAT_INFUSION', 'INFUSION_FLUID', 'Dịch truyền', 'Dịch truyền tĩnh mạch (NaCl 0.9%, Glucose 5%, Ringer Lactate)'),
('DCAT_VACCINE', 'VACCINE', 'Vắc-xin', 'Vắc-xin phòng bệnh (Cúm, Viêm gan B, HPV, COVID-19)');
